// qrcode.js - Standalone QR Code generator (based on qrcode-generator by Kazuhiko Arase, MIT License)
// Adapted for Chrome Extension use (no CDN, no eval, no dynamic imports)
(function(global){
'use strict';

var QRErrorCorrectLevel={L:1,M:0,Q:3,H:2};

function QRCode(options){
  if(typeof options==='string'){options={content:options};}
  this._options=Object.assign({ecl:'M',version:0},options);
  this._data=null;
  this._build();
}

QRCode.CorrectLevel=QRErrorCorrectLevel;

QRCode.prototype.modules=function(){return this._modules;};

QRCode.prototype._build=function(){
  var content=this._options.content||'';
  var ecl=this._options.ecl||'M';
  var eclVal;
  if(typeof ecl==='number'){eclVal=ecl;}
  else{
    var map={L:1,M:0,Q:3,H:2};
    eclVal=(map[String(ecl).toUpperCase()]!==undefined)?map[String(ecl).toUpperCase()]:0;
  }
  
  // encode data
  var bytes=[];
  for(var i=0;i<content.length;i++){
    var c=content.charCodeAt(i);
    if(c<128){bytes.push(c);}
    else if(c<2048){bytes.push((c>>6)|192);bytes.push((c&63)|128);}
    else{bytes.push((c>>12)|224);bytes.push(((c>>6)&63)|128);bytes.push((c&63)|128);}
  }
  
  // find minimum version
  var version=this._options.version||0;
  if(!version){
    for(var v=1;v<=40;v++){
      var cap=_getCapacity(v,eclVal);
      if(cap>=bytes.length){version=v;break;}
    }
  }
  if(!version){version=40;}
  
  this._modules=_createMatrix(version,eclVal,bytes);
};

// Capacity table (byte mode): [L,M,Q,H] for versions 1-40
var CAP=[[17,14,11,7],[32,26,20,14],[53,42,32,24],[78,62,46,34],[106,84,60,44],
[134,106,74,58],[154,122,86,64],[192,152,108,84],[230,180,130,98],[271,213,151,119],
[321,251,177,137],[367,287,203,155],[425,331,241,177],[458,362,258,194],[520,412,292,220],
[586,450,322,250],[644,504,364,280],[718,560,394,310],[792,624,442,338],[858,666,482,382],
[929,711,509,403],[1003,779,565,439],[1091,857,611,461],[1171,911,661,511],[1273,997,715,535],
[1367,1059,751,593],[1465,1125,805,625],[1528,1190,868,658],[1628,1264,908,698],[1732,1370,982,742],
[1840,1452,1030,790],[1952,1538,1112,842],[2068,1628,1168,898],[2188,1722,1228,958],[2303,1809,1283,983],
[2431,1911,1351,1051],[2563,1989,1423,1093],[2699,2099,1499,1139],[2809,2213,1579,1219],[2953,2331,1663,1273]];

function _getCapacity(v,ecl){return CAP[v-1]?CAP[v-1][ecl]||0:0;}

// Reed-Solomon GF(256)
var GF_EXP=new Array(512);
var GF_LOG=new Array(256);
(function(){var x=1;for(var i=0;i<255;i++){GF_EXP[i]=x;GF_LOG[x]=i;x<<=1;if(x&256)x^=285;}
for(var i=255;i<512;i++)GF_EXP[i]=GF_EXP[i-255];}());

function gfMul(a,b){if(!a||!b)return 0;return GF_EXP[(GF_LOG[a]+GF_LOG[b])%255];}
function gfPoly(deg,val){var p=new Array(deg+1).fill(0);p[0]=val;return p;}
function gfPolyMul(p,q){var r=new Array(p.length+q.length-1).fill(0);
for(var i=0;i<p.length;i++)for(var j=0;j<q.length;j++)r[i+j]^=gfMul(p[i],q[j]);return r;}
function gfPolyDiv(d,g){var r=d.slice();
for(var i=0;i<d.length-g.length+1;i++){var c=r[i];if(!c)continue;
for(var j=1;j<g.length;j++)r[i+j]^=gfMul(g[j],c);}return r.slice(d.length-g.length+1);}

function _rsGenerator(n){var g=[1];
for(var i=0;i<n;i++)g=gfPolyMul(g,[1,GF_EXP[i]]);return g;}

// QR error correction codewords per block info [ecCodewordsPerBlock, [[numBlocks,totalPerBlock,dataPerBlock],...]]
// format: [ecPerBlock, [[blocks,total,data],...]] for versions 1-7 and levels L,M,Q,H
var EC_INFO={
  '1L':[7,[[1,26,19]]],'1M':[10,[[1,26,16]]],'1Q':[13,[[1,26,13]]],'1H':[17,[[1,26,9]]],
  '2L':[10,[[1,44,34]]],'2M':[16,[[1,44,28]]],'2Q':[22,[[1,44,22]]],'2H':[28,[[1,44,16]]],
  '3L':[15,[[1,70,55]]],'3M':[26,[[1,70,44]]],'3Q':[18,[[2,35,17]]],'3H':[22,[[2,35,13]]],
  '4L':[20,[[1,100,80]]],'4M':[18,[[2,50,32]]],'4Q':[26,[[2,50,24]]],'4H':[16,[[4,25,9]]],
  '5L':[26,[[1,134,108]]],'5M':[24,[[2,67,43]]],'5Q':[18,[[2,33,15],[2,34,16]]],'5H':[22,[[2,33,11],[2,34,12]]],
  '6L':[18,[[2,86,68]]],'6M':[16,[[4,43,27]]],'6Q':[24,[[4,43,19]]],'6H':[28,[[4,43,15]]],
  '7L':[20,[[2,98,78]]],'7M':[18,[[4,49,31]]],'7Q':[18,[[2,32,14],[4,33,15]]],'7H':[26,[[4,39,13],[1,40,14]]],
  '8L':[24,[[2,121,97]]],'8M':[22,[[2,60,38],[2,61,39]]],'8Q':[22,[[4,40,18],[2,41,19]]],'8H':[26,[[4,40,14],[2,41,15]]],
  '9L':[30,[[2,146,116]]],'9M':[22,[[3,58,36],[2,59,37]]],'9Q':[20,[[4,36,16],[4,37,17]]],'9H':[24,[[4,36,12],[4,37,13]]],
  '10L':[18,[[2,86,68],[2,87,69]]],'10M':[26,[[4,69,43],[1,70,44]]],'10Q':[24,[[6,43,19],[2,44,20]]],'10H':[28,[[6,43,15],[2,44,16]]],
  '11L':[20,[[4,101,81]]],'11M':[30,[[1,80,50],[4,81,51]]],'11Q':[28,[[4,50,22],[4,51,23]]],'11H':[24,[[3,36,12],[8,37,13]]],
  '12L':[24,[[2,116,92],[2,117,93]]],'12M':[22,[[6,58,36],[2,59,37]]],'12Q':[26,[[4,46,20],[6,47,21]]],'12H':[28,[[7,42,14],[4,43,15]]],
  '13L':[26,[[4,133,107]]],'13M':[22,[[8,59,37],[1,60,38]]],'13Q':[24,[[8,44,20],[4,45,21]]],'13H':[22,[[12,33,11],[4,34,12]]],
  '14L':[30,[[3,145,115],[1,146,116]]],'14M':[24,[[4,64,40],[5,65,41]]],'14Q':[20,[[11,36,16],[5,37,17]]],'14H':[24,[[11,36,12],[5,37,13]]],
  '15L':[22,[[5,109,87],[1,110,88]]],'15M':[24,[[5,65,41],[5,66,42]]],'15Q':[30,[[5,54,24],[7,55,25]]],'15H':[24,[[11,36,12],[7,37,13]]],
  '16L':[24,[[5,122,98],[1,123,99]]],'16M':[28,[[7,73,45],[3,74,46]]],'16Q':[24,[[15,43,19],[2,44,20]]],'16H':[30,[[3,45,15],[13,46,16]]],
  '17L':[28,[[1,135,107],[5,136,108]]],'17M':[28,[[10,74,46],[1,75,47]]],'17Q':[28,[[1,50,22],[15,51,23]]],'17H':[28,[[2,42,14],[17,43,15]]],
  '18L':[30,[[5,150,120],[1,151,121]]],'18M':[26,[[9,69,43],[4,70,44]]],'18Q':[28,[[17,50,22],[1,51,23]]],'18H':[28,[[2,42,14],[19,43,15]]],
  '19L':[28,[[3,141,113],[4,142,114]]],'19M':[26,[[3,70,44],[11,71,45]]],'19Q':[26,[[17,47,21],[4,48,22]]],'19H':[26,[[9,39,13],[16,40,14]]],
  '20L':[28,[[3,135,107],[5,136,108]]],'20M':[26,[[3,67,41],[13,68,42]]],'20Q':[30,[[15,54,24],[5,55,25]]],'20H':[28,[[15,43,15],[2,44,16]]]
};

// For versions > 20, use a simplified approach
function _getEcInfo(v,ecl){
  var eclName=['M','L','H','Q'][ecl]; // map back
  var key=v+eclName;
  if(EC_INFO[key])return EC_INFO[key];
  // fallback for higher versions - approximate
  var dataBytes=CAP[v-1][ecl];
  var totalBytes=_totalCodewords(v);
  var ecBytes=totalBytes-dataBytes;
  return[Math.ceil(ecBytes/4),[[1,totalBytes,dataBytes]]];
}

function _totalCodewords(v){
  var total=[0,26,44,70,100,134,172,196,242,292,346,404,466,532,581,655,733,815,901,991,1085,
  1156,1258,1364,1474,1588,1706,1828,1921,2051,2185,2323,2465,2611,2761,2876,3034,3196,3362,3532,3706];
  return total[v]||0;
}

function _createMatrix(version,ecl,dataBytes){
  var N=version*4+17;
  var mat=[];
  var res=[];
  for(var i=0;i<N;i++){mat.push(new Array(N).fill(0));res.push(new Array(N).fill(false));}
  
  function set(r,c,v){if(r>=0&&r<N&&c>=0&&c<N){mat[r][c]=v;res[r][c]=true;}}
  
  // Finder patterns
  function finder(tr,tc){
    for(var dr=-1;dr<=7;dr++)for(var dc=-1;dc<=7;dc++){
      var v=0;
      if(dr>=0&&dr<=6&&dc>=0&&dc<=6){
        if(dr===0||dr===6||dc===0||dc===6)v=1;
        else if(dr>=2&&dr<=4&&dc>=2&&dc<=4)v=1;
        else v=0;
      }
      set(tr+dr,tc+dc,v?1:0);
    }
  }
  finder(0,0);finder(0,N-7);finder(N-7,0);
  
  // Timing
  for(var i=8;i<N-8;i++){set(6,i,i%2?0:1);set(i,6,i%2?0:1);}
  
  // Dark module
  set(N-8,8,1);
  
  // Alignment patterns
  var ap=_alignmentPositions(version);
  for(var ai=0;ai<ap.length;ai++)for(var aj=0;aj<ap.length;aj++){
    var ar=ap[ai],ac=ap[aj];
    if(res[ar][ac])continue;
    for(var dr=-2;dr<=2;dr++)for(var dc=-2;dc<=2;dc++){
      var v=(dr===-2||dr===2||dc===-2||dc===2)?1:(dr===0&&dc===0)?1:0;
      set(ar+dr,ac+dc,v);
    }
  }
  
  // Reserve format areas
  for(var i=0;i<8;i++){res[8][i]=true;res[i][8]=true;}
  res[8][8]=true;
  for(var i=N-8;i<N;i++){res[8][i]=true;res[i][8]=true;}
  // Version info areas (v>=7)
  if(version>=7){
    for(var r=0;r<6;r++)for(var c=N-11;c<N-8;c++){res[r][c]=true;res[c][r]=true;}
  }
  
  // Encode data
  var ecInfo=_getEcInfo(version,ecl);
  var ecPerBlock=ecInfo[0];
  var blocks=ecInfo[1];
  
  // Build data codewords
  var data=_encodeData(dataBytes,version,ecl,blocks,ecPerBlock);
  
  // Place data bits
  var bitIdx=0;
  var dir=-1;
  var row=N-1;
  for(var col=N-1;col>=0;col-=2){
    if(col===6)col--;
    for(var cnt=0;cnt<N;cnt++){
      var r=row;
      for(var right=0;right<2;right++){
        var c=col-right;
        if(!res[r][c]){
          var bit=(bitIdx<data.length*8)?((data[Math.floor(bitIdx/8)]>>(7-(bitIdx%8)))&1):0;
          mat[r][c]=bit;
          bitIdx++;
        }
      }
      row+=dir;
    }
    dir=-dir;
    row+=dir;
  }
  
  // Apply best mask
  var bestMask=0,bestPenalty=Infinity;
  for(var m=0;m<8;m++){
    var masked=_applyMask(mat,res,N,m);
    var p=_penalty(masked,N);
    if(p<bestPenalty){bestPenalty=p;bestMask=m;masked=masked;}
  }
  var finalMat=_applyMask(mat,res,N,bestMask);
  _writeFormat(finalMat,res,N,ecl,bestMask);
  if(version>=7)_writeVersion(finalMat,N,version);
  
  // Return boolean matrix
  var result=[];
  for(var r=0;r<N;r++){var row2=[];for(var c=0;c<N;c++)row2.push(!!finalMat[r][c]);result.push(row2);}
  return result;
}

function _alignmentPositions(v){
  if(v===1)return[];
  var n=Math.floor(v/7)+2;
  var last=v*4+10;
  var step=(v===32)?26:Math.ceil((last-6)/(n-1)/2)*2;
  var pos=[6];
  for(var i=n-2;i>=1;i--)pos.unshift(last-i*step);
  pos.push(last);
  return pos;
}

function _encodeData(bytes,version,ecl,blocks,ecPerBlock){
  // Mode: byte (0100), char count, data
  var totalData=CAP[version-1][ecl];
  var bitStream=[];
  
  function addBits(val,n){for(var i=n-1;i>=0;i--)bitStream.push((val>>i)&1);}
  
  addBits(4,4); // byte mode
  var ccLen=(version<10)?8:16;
  addBits(bytes.length,ccLen);
  for(var i=0;i<bytes.length;i++)addBits(bytes[i],8);
  // Terminator
  var termLen=Math.min(4,totalData*8-bitStream.length);
  for(var i=0;i<termLen;i++)bitStream.push(0);
  // Pad to byte boundary
  while(bitStream.length%8)bitStream.push(0);
  // Pad bytes
  var padBytes=[0xEC,0x11];var pi=0;
  while(bitStream.length<totalData*8){addBits(padBytes[pi%2],8);pi++;}
  
  // To bytes
  var dataWords=[];
  for(var i=0;i<bitStream.length;i+=8){
    var b=0;for(var j=0;j<8;j++)b=(b<<1)|bitStream[i+j];
    dataWords.push(b);
  }
  
  // Split into blocks and add EC
  var allData=[],allEc=[];
  var di=0;
  for(var bi=0;bi<blocks.length;bi++){
    var blockDef=blocks[bi];
    var numBlocks=blockDef[0],totalPerBlock=blockDef[1],dataPerBlock=blockDef[2];
    var ecPerB=totalPerBlock-dataPerBlock;
    var gen=_rsGenerator(ecPerB);
    for(var b=0;b<numBlocks;b++){
      var block=dataWords.slice(di,di+dataPerBlock);di+=dataPerBlock;
      var ec=gfPolyDiv(block.concat(new Array(ecPerB).fill(0)),gen);
      allData.push(block);allEc.push(ec);
    }
  }
  
  // Interleave
  var result=[];
  var maxData=Math.max.apply(null,allData.map(function(b){return b.length;}));
  for(var i=0;i<maxData;i++)for(var b=0;b<allData.length;b++)if(i<allData[b].length)result.push(allData[b][i]);
  var maxEc=Math.max.apply(null,allEc.map(function(b){return b.length;}));
  for(var i=0;i<maxEc;i++)for(var b=0;b<allEc.length;b++)if(i<allEc[b].length)result.push(allEc[b][i]);
  
  return result;
}

function _applyMask(mat,res,N,m){
  var out=[];
  for(var r=0;r<N;r++){out.push(mat[r].slice());}
  var fn=[
    function(r,c){return(r+c)%2===0;},
    function(r,c){return r%2===0;},
    function(r,c){return c%3===0;},
    function(r,c){return(r+c)%3===0;},
    function(r,c){return(Math.floor(r/2)+Math.floor(c/3))%2===0;},
    function(r,c){return(r*c)%2+(r*c)%3===0;},
    function(r,c){return((r*c)%2+(r*c)%3)%2===0;},
    function(r,c){return((r+c)%2+(r*c)%3)%2===0;}
  ][m];
  for(var r=0;r<N;r++)for(var c=0;c<N;c++)if(!res[r][c]&&fn(r,c))out[r][c]^=1;
  return out;
}

function _penalty(mat,N){
  var p=0;
  // Rule 1: 5+ in a row
  for(var r=0;r<N;r++){var run=1;for(var c=1;c<N;c++){if(mat[r][c]===mat[r][c-1])run++;else{if(run>=5)p+=run-2;run=1;}if(run>=5)p+=run-2;}}
  for(var c=0;c<N;c++){var run=1;for(var r=1;r<N;r++){if(mat[r][c]===mat[r-1][c])run++;else{if(run>=5)p+=run-2;run=1;}if(run>=5)p+=run-2;}}
  // Rule 2: 2x2 blocks
  for(var r=0;r<N-1;r++)for(var c=0;c<N-1;c++)if(mat[r][c]===mat[r+1][c]&&mat[r][c]===mat[r][c+1]&&mat[r][c]===mat[r+1][c+1])p+=3;
  // Rule 4: dark/light ratio
  var dark=0;for(var r=0;r<N;r++)for(var c=0;c<N;c++)dark+=mat[r][c];
  var pct=Math.abs(dark/(N*N)-.5)*20;p+=Math.floor(pct)*10;
  return p;
}

function _writeFormat(mat,res,N,ecl,mask){
  // QR spec ECL format bits: M=00(0), L=01(1), H=10(2), Q=11(3)
  // Library ecl values:       0=M,    1=L,     2=H,     3=Q  => identity mapping
  var eclBits=ecl;
  var data=(eclBits<<3)|mask;
  // BCH(15,5) remainder, generator polynomial 0x537
  var rem=data<<10;
  for(var i=14;i>=10;i--){if(rem&(1<<i))rem^=(0x537<<(i-10));}
  var fmt=((data<<10)|(rem&0x3FF))^0x5412;
  var bits=[];for(var i=14;i>=0;i--)bits.push((fmt>>i)&1);
  var pos1=[[8,0],[8,1],[8,2],[8,3],[8,4],[8,5],[8,7],[8,8],[7,8],[5,8],[4,8],[3,8],[2,8],[1,8],[0,8]];
  var pos2=[[N-1,8],[N-2,8],[N-3,8],[N-4,8],[N-5,8],[N-6,8],[N-7,8],[8,N-8],[8,N-7],[8,N-6],[8,N-5],[8,N-4],[8,N-3],[8,N-2],[8,N-1]];
  for(var i=0;i<15;i++){mat[pos1[i][0]][pos1[i][1]]=bits[i];mat[pos2[i][0]][pos2[i][1]]=bits[i];}
}

function _writeVersion(mat,N,v){
  var g=0x1F25;var rem=v;
  for(var i=0;i<12;i++)rem=(rem<<1)^((rem>>11)?g:0);
  var vinfo=(v<<12)|rem;
  for(var i=0;i<18;i++){var bit=(vinfo>>i)&1;var r=Math.floor(i/3),c=N-11+i%3;mat[r][c]=bit;mat[c][r]=bit;}
}

// Public API compatible with qrcodejs
function QRCodeWidget(el, options){
  if(typeof options==='string')options={text:options};
  this._el=el;
  this._options=Object.assign({width:256,height:256,colorDark:'#000000',colorLight:'#ffffff',correctLevel:QRErrorCorrectLevel.M},options);
  this._make();
}
QRCodeWidget.CorrectLevel=QRErrorCorrectLevel;
QRCodeWidget.prototype._make=function(){
  var text=this._options.text||'';
  var ecl=this._options.correctLevel;
  var eclStr=['M','L','H','Q'][ecl]||'M';
  var qr=new QRCode({content:text,ecl:eclStr});
  var mods=qr.modules();
  var n=mods.length;
  var w=this._options.width,h=this._options.height;
  var canvas=document.createElement('canvas');
  canvas.width=w;canvas.height=h;
  var ctx=canvas.getContext('2d');
  ctx.fillStyle=this._options.colorLight;ctx.fillRect(0,0,w,h);
  var cell=w/n;
  ctx.fillStyle=this._options.colorDark;
  for(var r=0;r<n;r++)for(var c=0;c<n;c++)if(mods[r][c])ctx.fillRect(Math.floor(c*cell),Math.floor(r*cell),Math.ceil(cell),Math.ceil(cell));
  this._canvas=canvas;
  this._el.innerHTML='';this._el.appendChild(canvas);
};
QRCodeWidget.prototype.makeCode=function(text){this._options.text=text;this._make();};
QRCodeWidget.prototype.clear=function(){this._el.innerHTML='';};

// Export
global.QRCode=QRCodeWidget;
global.QRCodeRaw=QRCode;

}(typeof window!=='undefined'?window:this));
